    bool initial_or = or_expr.get();

    // Update variables to trigger recomputation
    var1.set(!a);  // Flip the value to trigger change
    var2.set(!b);  // Flip the value to trigger change

    // Get updated AND and OR results
    bool updated_and = and_expr.get();
    bool updated_or = or_expr.get();

    return LogicalExpressionSnapshot{
        initial_and,
        initial_or, 
        updated_and,
        updated_or
    };
}

