    reaction::atomicMultiplyAssign(atomicImpl, 3);
    bool multiplyReportedChange = atomicImpl.lastReportedChange();

    // Apply atomic bitwise AND assignment
    reaction::atomicBitwiseAndAssign(atomicImpl, 0x0F);
    bool andReportedChange = atomicImpl.lastReportedChange();

    // Apply atomic left shift assignment
    reaction::atomicLeftShiftAssign(atomicImpl, 2);
    bool leftShiftReportedChange = atomicImpl.lastReportedChange();

    // Apply atomic increment
    reaction::atomicIncrement(atomicImpl);
    bool incrementReportedChange = atomicImpl.lastReportedChange();

    // Get final value
    int32_t finalValue = atomicImpl.value();

    return AtomicHelperSnapshot{
        finalValue,
        addReportedChange,
        multiplyReportedChange,
        andReportedChange,
        leftShiftReportedChange,
        incrementReportedChange
    };
}

